module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output reg valid_out,
    output reg dout
);

reg [1:0] cnt;
reg [3:0] data;
reg valid;

always @(*) begin
    dout = data[3];
    valid_out = valid;
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin

        cnt <= 2'b0;
        data <= 4'b0;
        valid <= 1'b0;
    end else begin

        if (cnt == 2'b11) begin

            data <= d;
            cnt <= 2'b0;
            valid <= 1'b1;
        end else begin

            data <= {data[2:0], data[3]};
            cnt <= cnt + 1;
            valid <= 1'b0;
        end
    end
end
endmodule
